const https = require('https');

function httpReq(url, options = {}) {
  return new Promise((resolve, reject) => {
    const m = url.match(/^https?:\/\/([^/]+)(\/.*)$/);
    if (!m) { reject(new Error('Invalid URL: ' + url)); return; }
    const hostname = m[1];
    const path = m[2] || '/';
    const postData = options.body || '';
    const req = https.request({
      hostname: hostname,
      port: 443,
      path: path,
      method: options.method || 'GET',
      headers: { ...options.headers, ...(postData ? { 'Content-Length': Buffer.byteLength(postData) } : {}) }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const body = Buffer.concat(chunks).toString();
        resolve({ ok: res.statusCode >= 200 && res.statusCode < 300, status: res.statusCode, text: () => Promise.resolve(body), json: () => Promise.resolve(JSON.parse(body)), headers: res.headers });
      });
    });
    req.on('error', reject);
    req.setTimeout(15000, () => { req.destroy(); reject(new Error('Request timeout')); });
    if (postData) req.write(postData);
    req.end();
  });
}

const SUPABASE_URL = 'https://prometeix-servidor-supabase.reyl9a.easypanel.host/rest/v1';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyAgCiAgICAicm9sZSI6ICJzZXJ2aWNlX3JvbGUiLAogICAgImlzcyI6ICJzdXBhYmFzZS1kZW1vIiwKICAgICJpYXQiOiAxNjQxNzY5MjAwLAogICAgImV4cCI6IDE3OTk1MzU2MDAKfQ.DaYlNEoUrrEn2Ig7tqibS-PHK5vgusbcbo7X36XVt4Q';
const sbHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY,
  'Content-Type': 'application/json'
};

const input = $input.first().json;
const body = input.body || input;
const { token, vendor_id, status_filter, page, page_size } = body;

if (!token || !vendor_id) {
  return [{ json: { success: false, error: 'Missing token or vendor_id' } }];
}

try {
  // Auth
  const authResp = await httpReq('https://api.katalync.com/webhook/auth-verify', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ token })
  });
  const authData = await authResp.json();
  if (!authData.success) {
    return [{ json: { success: false, error: authData.error || 'Token invalid or expired' } }];
  }

  // Upsert user
  const upsertData = await httpReq(SUPABASE_URL + '/users?on_conflict=email', {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'resolution=merge-duplicates,return=representation' },
    body: JSON.stringify([{ email: authData.email, name: authData.name || authData.email, password_hash: 'oauth-managed', role: authData.role || 'user', company: authData.company || null, lang: authData.lang || 'es', onboarded: authData.onboarded || false, subscription_status: authData.subscription_status || 'active', last_login_at: new Date().toISOString() }])
  });
  const userData = await upsertData.json();
  const user_id = userData && userData.length > 0 ? userData[0].id : null;
  if (!user_id) return [{ json: { success: false, error: 'Failed to provision user' } }];

  // Verify vendor ownership (admins can access all vendors)
  const isAdmin = authData.role === 'admin' || authData.role === 'super_admin';
  const vendorQuery = isAdmin
    ? SUPABASE_URL + '/vendors?id=eq.' + vendor_id + '&select=id,name'
    : SUPABASE_URL + '/vendors?id=eq.' + vendor_id + '&user_id=eq.' + user_id + '&select=id,name';
  const vendorsResp = await httpReq(vendorQuery, {
    headers: sbHeaders
  });
  const vendors = await vendorsResp.json();
  if (!Array.isArray(vendors) || vendors.length === 0) {
    return [{ json: { success: false, error: 'Vendor not found or access denied' } }];
  }

  // Build query
  const limit = Math.min(page_size || 50, 200);
  const offset = ((page || 1) - 1) * limit;
  let filter = '&vendor_id=eq.' + vendor_id;
  if (status_filter === 'converted') filter += '&sprinter_product=not.is.null';
  else if (status_filter === 'pending') filter += '&sprinter_product=is.null';

  // Fetch products
  const productsResp = await httpReq(SUPABASE_URL + '/vendor_products?select=id,sku,ean,name,brand,category,price,stock,image_url,converted_image_url,sprinter_product,sprinter_offer,sync_status,last_synced_at,raw_data' + filter + '&order=created_at.desc&limit=' + limit + '&offset=' + offset, {
    headers: { ...sbHeaders, 'Prefer': 'count=exact' }
  });

  const products = await productsResp.json();
  const totalHeader = productsResp.headers['content-range'];
  let total = Array.isArray(products) ? products.length : 0;
  if (totalHeader) {
    const match = totalHeader.match(/\/(\d+)/);
    if (match) total = parseInt(match[1], 10);
  }

  // Summary counts
  const convertedCount = Array.isArray(products) ? products.filter(p => p.sprinter_product && Object.keys(p.sprinter_product).length > 0).length : 0;
  const pendingCount = Array.isArray(products) ? products.filter(p => !p.sprinter_product || Object.keys(p.sprinter_product).length === 0).length : 0;

  // Expand products per marketplace (1 product with ES+PT -> 2 entries)
  const simplified = [];
  for (const p of (Array.isArray(products) ? products : [])) {
    const sp = p.sprinter_product || {};
    const so = p.sprinter_offer || {};
    const hasDiscount = p.raw_data && p.raw_data.compare_at_price && parseFloat(p.raw_data.compare_at_price) > (p.price || 0);
    const mktKeys = Object.keys(sp).filter(k => k.includes('sprinter') || k.includes('sportzone'));
    if (mktKeys.length > 0) {
      for (const mkt of mktKeys) {
        const spd = sp[mkt] || {};
        const sod = so[mkt] || {};
        simplified.push({
          id: p.id + '-' + mkt,
          sku: p.sku,
          ean: p.ean,
          name: p.name,
          brand: p.brand,
          category: p.category,
          price: p.price,
          stock: p.stock,
          image_url: p.image_url,
          converted_image_url: p.converted_image_url || spd['imagenes-1'] || null,
          sprinter_title: spd['nombre-del-articulo'] || null,
          sprinter_category: spd['categorias'] || null,
          sprinter_description: (spd['descripion-del-producto'] || '').substring(0, 150) || null,
          sprinter_color: spd['colores'] || null,
          sprinter_size: spd['talla'] || null,
          offer_price: sod['price'] || null,
          offer_discount: sod['discount-price'] || null,
          offer_quantity: sod['quantity'] || null,
          sync_status: p.sync_status,
          is_converted: true,
          has_discount: hasDiscount,
          marketplace: mkt,
          last_synced_at: p.last_synced_at
        });
      }
    } else {
      simplified.push({
        id: p.id,
        sku: p.sku,
        ean: p.ean,
        name: p.name,
        brand: p.brand,
        category: p.category,
        price: p.price,
        stock: p.stock,
        image_url: p.image_url,
        converted_image_url: p.converted_image_url || null,
        sprinter_title: null,
        sprinter_category: null,
        sprinter_description: null,
        sprinter_color: null,
        sprinter_size: null,
        offer_price: null,
        offer_discount: null,
        offer_quantity: null,
        sync_status: p.sync_status,
        is_converted: false,
        has_discount: hasDiscount,
        marketplace: null,
        last_synced_at: p.last_synced_at
      });
    }
  }

  return [{ json: {
    success: true,
    products: simplified,
    total: total,
    page: page || 1,
    page_size: limit,
    converted_in_page: convertedCount,
    pending_in_page: pendingCount
  } }];

} catch (e) {
  return [{ json: { success: false, error: 'Server error: ' + e.message } }];
}
